import (
	"math"
	"strings"
)

func solve(s string) int64 {
	freq := make(map[rune]int)
	for _, char := range s {
		freq[char]++
	}

	getMirrorChar := func(char rune) rune {
		code := char
		if code >= 'a' && code <= 'z' {
			// Lowercase letter
			// 'a' is 0, 'z' is 25
			// Mirror of position i is 25 - i
			pos := int(code - 'a')
			mirrorPos := 25 - pos
			return rune('a' + mirrorPos)
		} else if code >= '0' && code <= '9' {
			// Digit
			digit := int(code - '0')
			mirrorDigit := 9 - digit
			return rune('0' + mirrorDigit)
		}
		return 0 // Should not happen
	}

	var totalDifference int64 = 0
	// Use a map to track which characters have already been processed as part of a pair
	processed := make(map[rune]bool)

	// Iterate over unique characters present in the string
	for c := range freq {
		if processed[c] {
			continue
		}

		m := getMirrorChar(c)
		if m == 0 {
			continue // Invalid character
		}

		// Ensure we process the pair (c, m) only once.
		// We enforce an ordering rule to avoid double counting.
		// If c == m (e.g., 'm' <-> 'n' is not a self-mirror in this context, but a character might mirror to itself if it were, e.g., 'm' mirrors to 'n' not 'm' based on standard definitions, but for self-mirroring elements, we handle them once).
