		if c == m {
			freqC := int64(freq[c])
			freqM := freqC // freq(m) is the same as freq(c)
			difference := int64(math.Abs(float64(freqC) - float64(freqM)))
			totalDifference += difference
			processed[c] = true
			continue
		}

		// Standard case: c != m
		// To ensure we only calculate for {c, m} once, we only proceed if c is lexicographically smaller than m.
		// If c > m, then m will be encountered later in the loop, and the pair {m, c} will be processed then.
		if c > m {
			continue
		}

		// Now we have the canonical pair {c, m} where c < m (or c=m which was handled above)

		freqC := int64(freq[c])
		freqM := int64(freq[m])

		// Calculate absolute difference
